package main.rice.concisegen;

import main.rice.test.TestCase;
import main.rice.test.TestResults;

import java.util.*;

/**
 * Selects a minimal set of test cases that covers all buggy implementations,
 * using a greedy set cover algorithm.
 */
public class ConciseSetGenerator {

    /**
     * Given test results, returns a minimal subset of test cases that together catch
     * all buggy implementations (i.e., all implementations in wrongSet).
     *
     * Uses a greedy algorithm: repeatedly pick the test case that catches the most
     * not-yet-covered buggy implementations, until all are covered.
     *
     * Does NOT mutate the input TestResults object.
     *
     * @param results the results of running tests on multiple implementations
     * @return a minimal list of test cases that catches all buggy implementations
     */
    public static List<TestCase> setCover(TestResults results) {
        // Work with copies to avoid mutating the input
        List<Set<Integer>> caseToFiles = new ArrayList<>();
        for (Set<Integer> s : results.getCaseToFiles()) {
            caseToFiles.add(new HashSet<>(s));
        }
        Set<Integer> remaining = new HashSet<>(results.getWrongSet());

        List<TestCase> chosen = new ArrayList<>();

        // Track which test indices have already been selected
        Set<Integer> usedIndices = new HashSet<>();

        while (!remaining.isEmpty()) {
            int bestIndex = -1;
            int bestCount = -1;

            // Find the test case that covers the most remaining buggy files
            for (int i = 0; i < caseToFiles.size(); i++) {
                if (usedIndices.contains(i)) {
                    continue;
                }
                // Count how many remaining buggy files this test covers
                Set<Integer> intersection = new HashSet<>(caseToFiles.get(i));
                intersection.retainAll(remaining);
                int count = intersection.size();

                if (count > bestCount) {
                    bestCount = count;
                    bestIndex = i;
                }
            }

            // If no test covers any remaining file, we can't make progress — break
            if (bestIndex == -1 || bestCount == 0) {
                break;
            }

            // Add the best test case to our chosen set
            chosen.add(results.getTestCase(bestIndex));
            usedIndices.add(bestIndex);

            // Remove the files covered by this test from remaining
            remaining.removeAll(caseToFiles.get(bestIndex));
        }

        return chosen;
    }
}

