package main.rice.node;

import main.rice.obj.APyObj;

import java.util.ArrayList;
import java.util.List;
import java.util.Random;

/**
 * An abstract class representing a node in a tree structure for generating Python objects.
 * Each node has an exhaustive domain and a random domain, and can generate values from them.
 *
 * @param <T> the type of domain values (e.g., Integer, Double)
 * @param <R> the type of PyObj produced (e.g., PyIntObj, PyFloatObj)
 */
public abstract class APyNode<T, R extends APyObj> {

    /**
     * The exhaustive domain: list of values from which exhaustive test cases are generated.
     */
    private List<T> exDomain;

    /**
     * The random domain: list of values from which random test cases are generated.
     */
    private List<T> ranDomain;

    /**
     * Random number generator for generating random values.
     */
    protected static final Random rand = new Random();

    /**
     * Sets the exhaustive domain.
     *
     * @param exDomain the exhaustive domain
     */
    public void setExDomain(List<T> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Sets the random domain.
     *
     * @param ranDomain the random domain
     */
    public void setRanDomain(List<T> ranDomain) {
        this.ranDomain = ranDomain;
    }

    /**
     * Returns the exhaustive domain.
     *
     * @return the exhaustive domain
     */
    public List<T> getExDomain() {
        return this.exDomain;
    }

    /**
     * Returns the random domain.
     *
     * @return the random domain
     */
    public List<T> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Returns the left child of this node, or null if this is a leaf node.
     *
     * @return the left child, or null
     */
    public abstract APyNode<?, ?> getLeftChild();

    /**
     * Returns the right child of this node, or null if this is a leaf node.
     *
     * @return the right child, or null
     */
    public abstract APyNode<?, ?> getRightChild();

    /**
     * Generates all values in the exhaustive domain as PyObj instances.
     *
     * @return a list of all values in the exhaustive domain
     */
    public List<R> genExVals() {
        List<R> result = new ArrayList<>();
        for (T val : this.exDomain) {
            result.add(this.wrap(val));
        }
        return result;
    }

    /**
     * Generates a single random value from the random domain as a PyObj instance.
     *
     * @return a randomly selected value from the random domain
     */
    public R genRandVal() {
        int index = rand.nextInt(this.ranDomain.size());
        return this.wrap(this.ranDomain.get(index));
    }

    /**
     * Wraps a domain value in the appropriate PyObj subclass.
     *
     * @param val the value to wrap
     * @return the wrapped PyObj
     */
    protected abstract R wrap(T val);
}

package main.rice.node;

import main.rice.obj.PyBoolObj;

/**
 * A node for generating PyBoolObj values.
 * Domain values are integers: 0 represents False, 1 represents True.
 */
public class PyBoolNode extends APyNode<Integer, PyBoolObj> {

    /**
     * Returns null, since PyBoolNode is a leaf node.
     *
     * @return null
     */
    @Override
    public APyNode<?, ?> getLeftChild() {
        return null;
    }

    /**
     * Returns null, since PyBoolNode is a leaf node.
     *
     * @return null
     */
    @Override
    public APyNode<?, ?> getRightChild() {
        return null;
    }

    /**
     * Wraps an integer domain value (0 or 1) into a PyBoolObj.
     *
     * @param val the integer value (0 = False, 1 = True)
     * @return a PyBoolObj with the corresponding boolean value
     */
    @Override
    protected PyBoolObj wrap(Integer val) {
        return new PyBoolObj(val != 0);
    }
}

